923: /**
924:  * Compute context convergence signals from raw node and edge data.
925:  *
926:  * Pure (no DB) so both computeContextSignals and the convergence script share
927:  * one implementation. Agreement is read from a node's CONFIRMS in-edges OR its
928:  * metadata.confirmations (whichever is higher); relevance from metadata.relevance.
929:  * Each signal vacuous-passes (1.0) when its kind is absent so a feature with no
930:  * dependencies (etc.) is not penalized — matching the review p0ResolutionRate rule.
931:  *
932:  * @param nodes - Coverage nodes for the namespace.
933:  * @param edges - Coverage edges for the namespace.
934:  * @returns Context convergence signals with all five metrics.
935:  */
936: export function computeContextSignalsFromData(
937:   nodes: CoverageNode[],
938:   edges: CoverageEdge[],
939: ): ContextConvergenceSignals {
940:   const sliceNodes = nodes.filter((node) => node.kind === 'SLICE');
941:   const reuseNodes = nodes.filter((node) => node.kind === 'REUSE_CANDIDATE');
942:   const dependencyNodes = nodes.filter((node) => node.kind === 'DEPENDENCY');
943:   const findingKinds = new Set(['REUSE_CANDIDATE', 'PATTERN', 'CONSTRAINT']);
944:   const findingNodes = nodes.filter((node) => findingKinds.has(node.kind));
945: 
946:   const coveredSliceIds = new Set(
947:     edges.filter((edge) => edge.relation === 'COVERED_BY').map((edge) => edge.sourceId),
948:   );
949:   const confirmCountById = new Map<string, number>();
950:   for (const edge of edges) {
